<?php
$statusMeta = [
    'open' => ['Berjalan', 35, 'bg-amber-50 text-orange-600'],
    'submitted' => ['Menunggu Review', 100, 'bg-amber-50 text-orange-600'],
    'approved' => ['Selesai', 100, 'bg-green-50 text-green-600'],
    'rejected' => ['Perlu Revisi', 55, 'bg-red-50 text-red-600'],
];
[$statusLabel, $taskProgress, $statusTone] = $statusMeta[$task['status']] ?? [$task['status'], 0, 'bg-slate-100 text-slate-600'];
$deadlineDays = (int)ceil((strtotime($task['deadline_at']) - time()) / 86400);
$isOverdue = $task['status'] !== 'approved' && $deadlineDays < 0;
if ($isOverdue) [$statusLabel, $statusTone] = ['Terlambat', 'bg-red-50 text-red-600'];
if ($task['status'] === 'approved' || $deadlineDays > 7) [$priority, $priorityTone] = ['Rendah', 'bg-green-50 text-green-600'];
elseif ($deadlineDays > 3) [$priority, $priorityTone] = ['Sedang', 'bg-amber-50 text-amber-600'];
else [$priority, $priorityTone] = ['Mendesak', 'bg-red-50 text-red-600'];
$latestSubmission = $subs[0] ?? null;
$reviewerName = $latestSubmission['reviewer_name'] ?? ($canReviewTask ? $user['name'] : $task['creator_name']);
$reviewerRole = $canReviewTask ? role_label($user['role']) : 'Project Manager';
?>
