  <div><small>Assignee</small><b class="task-review-person"><i><?= e(strtoupper(substr($currentAssignees[0]['name']??'-',0,1))) ?></i><?= e($currentAssignees[0]['name']??'-') ?></b><span><?= e(count($currentAssignees)) ?> penerima task</span></div>
