      <article class="task-review-card"><h2>Checklist Workflow</h2><ul class="task-review-checklist"><li class="is-done">Task telah dibuat</li><li class="<?= $subs?'is-done':'' ?>">Bukti pekerjaan dikirim</li><li class="<?= $task['status']==='submitted'?'is-done':'' ?>">Menunggu keputusan reviewer</li><li class="<?= $task['status']==='approved'?'is-done':'' ?>">Review disetujui</li></ul></article>
     </div>
    </div>
   </div>
   <div class="task-review-panel" data-review-panel="description"><article class="task-review-card"><h2>Deskripsi Task</h2><p class="task-review-copy"><?= nl2br(e($task['description'] ?: 'Tidak ada deskripsi task.')) ?></p><dl><div><dt>Dibuat oleh</dt><dd><?= e($task['creator_name']) ?></dd></div><div><dt>Dibuat pada</dt><dd><?= e(date('d M Y, H:i',strtotime($task['created_at']))) ?></dd></div></dl></article></div>
   <div class="task-review-panel" data-review-panel="history"><article class="task-review-card"><h2>Riwayat Submit & Review</h2><div class="task-review-history"><?php foreach($subs as $s): ?><div><span class="<?= e($s['status']) ?>"><?= e(get_task_status_label($s['status'])) ?></span><b><?= e($s['submitter_name']) ?></b><small><?= e(date('d M Y, H:i',strtotime($s['created_at']))) ?></small><p><?= e($s['review_note'] ?: $s['note']) ?></p></div><?php endforeach; ?><?php if(!$subs): ?><p class="task-review-empty">Belum ada riwayat submission.</p><?php endif; ?></div></article></div>
   <div class="task-review-panel" data-review-panel="attachments"><article class="task-review-card"><h2>Semua Lampiran</h2><div class="task-review-files"><?php foreach($subs as $s): if(!$s['file_path'])continue; ?><div><i>FILE</i><span><b><?= e(basename($s['file_path'])) ?></b><small><?= e($s['submitter_name']) ?></small></span><a href="<?= e(app_url($s['file_path'])) ?>" target="_blank">Buka</a></div><?php endforeach; ?></div></article></div>
   <div class="task-review-panel" data-review-panel="comments"><article class="task-review-card"><h2>Diskusi Task</h2><div class="task-review-comments"><?php foreach($comments as $comment): ?><div><i><?= e(strtoupper(substr($comment['name'],0,1))) ?></i><span><b><?= e($comment['name']) ?></b><small><?= e(date('d M Y, H:i',strtotime($comment['created_at']))) ?></small><p><?= e($comment['body']) ?></p></span></div><?php endforeach; ?></div><form method="post" action="<?= e(app_url('actions/task-comment.php')) ?>"><input type="hidden" name="action" value="add_comment"><input type="hidden" name="task_id" value="<?= e($taskId) ?>"><?= csrf_field() ?><input id="taskCommentInput" name="body" placeholder="Tulis komentar..." required><button>Kirim</button></form></article></div>
   <footer class="task-review-note">Setelah review dikirim, assignee akan menerima notifikasi dan dapat melihat feedback pada riwayat task.</footer>
  </section>

  <aside class="task-review-aside">
   <section><h2>Reviewer</h2><div class="task-review-reviewer"><i><?= e(strtoupper(substr($reviewerName,0,1))) ?></i><span><b><?= e($reviewerName) ?></b><small><?= e($reviewerRole) ?></small></span></div></section>
   <?php if($canReviewTask&&$hasSubmittedProof): ?><form method="post" action="<?= e(app_url('actions/task-review.php')) ?>" class="task-review-decision"><?= csrf_field() ?><input type="hidden" name="task_id" value="<?= e($taskId) ?>"><h3>Keputusan Review <b>*</b></h3><div><label><input type="radio" name="decision" value="approved" required><span class="approve"><b>Setujui</b><small>Terima hasil kerja</small></span></label><label><input type="radio" name="decision" value="rejected" required><span class="revise"><b>Minta Revisi</b><small>Perlu perbaikan</small></span></label></div><label class="task-review-note-field"><b>Catatan untuk Assignee</b><textarea name="review_note" rows="7" placeholder="Tulis catatan review di sini..."></textarea><small>Wajib diisi ketika meminta revisi.</small></label><button type="submit">Kirim Review</button></form><?php else: ?><section class="task-review-unavailable"><h3>Keputusan Review</h3><p><?= $canReviewTask?'Belum ada bukti submit yang menunggu review.':'Role kamu tidak memiliki akses untuk mereview task ini.' ?></p></section><?php endif; ?>
