  </aside>
 </div>
</main>
<?php if($canSubmitTask): ?><div class="submit-task-modal fixed inset-0 z-50 hidden items-center justify-center bg-slate-950/55 p-4 backdrop-blur-sm"><form class="task-detail-modal w-full max-w-xl rounded-3xl bg-white p-6 shadow-2xl" method="post" action="<?= e(app_url('actions/task-submit.php')) ?>" enctype="multipart/form-data"><?= csrf_field() ?><input type="hidden" name="task_id" value="<?= e($taskId) ?>"><div class="flex justify-between"><h3 class="text-xl font-black">Submit Bukti Pekerjaan</h3><button class="close-submit-modal text-2xl" type="button">×</button></div><textarea class="mt-5 w-full rounded-xl border border-slate-200 p-4" name="note" rows="4" placeholder="Catatan pekerjaan..." required></textarea><input class="mt-4 w-full rounded-xl border border-slate-200 p-3" name="proof_file" type="file"><button class="mt-5 w-full rounded-xl bg-orange-600 px-5 py-3 font-black text-white">Kirim Bukti</button></form></div><?php endif; ?>
<?php if($canEditTask&&!task_has_locked_review($pdo,$taskId)): ?><div class="edit-task-modal fixed inset-0 z-50 <?= $taskError?'flex':'hidden' ?> items-center justify-center bg-slate-950/55 p-4 backdrop-blur-sm"><form class="task-detail-modal max-h-[92vh] w-full max-w-2xl overflow-y-auto rounded-3xl bg-white p-6 shadow-2xl" method="post"><?= csrf_field() ?><input type="hidden" name="action" value="update_task"><div class="flex justify-between"><h3 class="text-xl font-black">Edit Task</h3><button class="close-edit-task text-2xl" type="button">×</button></div><input class="mt-5 w-full rounded-xl border border-slate-200 px-4 py-3" name="title" value="<?= e($task['title']) ?>" required><textarea class="mt-4 w-full rounded-xl border border-slate-200 p-4" name="description" rows="3"><?= e($task['description']) ?></textarea><input class="mt-4 w-full rounded-xl border border-slate-200 px-4 py-3" type="datetime-local" name="deadline_at" value="<?= e(date('Y-m-d\TH:i',strtotime($task['deadline_at']))) ?>" required><div class="mt-4 grid gap-2 md:grid-cols-2"><?php foreach($editableAssignees as $candidate): ?><label class="flex gap-3 rounded-xl border border-slate-200 p-3"><input type="checkbox" name="assignee_ids[]" value="<?= e($candidate['id']) ?>" <?= in_array((int)$candidate['id'],$currentAssigneeIds,true)?'checked':'' ?>><span><b class="block text-sm"><?= e($candidate['name']) ?></b><small><?= e($candidate['role']) ?></small></span></label><?php endforeach; ?></div><button class="mt-5 w-full rounded-xl bg-orange-600 px-5 py-3 font-black text-white">Simpan Task</button></form></div><?php endif; ?>
