<script>(()=>{const tabs=document.querySelectorAll('[data-review-tab]'),panels=document.querySelectorAll('[data-review-panel]');tabs.forEach(t=>t.addEventListener('click',()=>{tabs.forEach(x=>x.classList.toggle('is-active',x===t));panels.forEach(p=>p.classList.toggle('is-active',p.dataset.reviewPanel===t.dataset.reviewTab))}));const reviewForm=document.querySelector('.task-review-decision'),reviewNote=reviewForm?.querySelector('[name=review_note]');reviewForm?.querySelectorAll('[name=decision]').forEach(input=>input.addEventListener('change',()=>{if(reviewNote)reviewNote.required=input.value==='rejected'}));const bind=(open,modal,close)=>{const panel=document.querySelector(modal);document.querySelectorAll(open).forEach(b=>b.addEventListener('click',()=>{panel?.classList.remove('hidden');panel?.classList.add('flex')}));document.querySelectorAll(close).forEach(b=>b.addEventListener('click',()=>{panel?.classList.add('hidden');panel?.classList.remove('flex')}));panel?.addEventListener('click',e=>{if(e.target===panel){panel.classList.add('hidden');panel.classList.remove('flex')}})};bind('.open-submit-modal','.submit-task-modal','.close-submit-modal');bind('.open-edit-task','.edit-task-modal','.close-edit-task');bind('.open-reopen-modal','.reopen-task-modal','.close-reopen-modal')})();</script>
